-- Version : 6.0 (Production Ready — All Bugs Fixed)
-- Target  : Supabase PostgreSQL 15+
-- Author  : Generated by AI (Software Engineer + DBA + CyberSec)
--
-- CHANGELOG dari v5.0.1:
-- [FIX-1]  customer_debts.remaining  → GENERATED ALWAYS AS STORED
-- [FIX-2]  shifts.cash_difference    → GENERATED ALWAYS AS STORED
-- [FIX-3]  Trigger deadlock: fn_block_direct_stock_update dihapus,
--           diganti pendekatan SECURITY DEFINER yang aman
-- [FIX-4]  NOT NULL diterapkan ke kolom nullable kritis
-- [FIX-5]  stock_movements.reference_type → pakai ENUM bukan text
-- [FIX-6]  inherit_cost_price dipindah ke product_variants (benar)
-- [FIX-7]  fn_record_initial_stock: fallback admin untuk migration
-- [FIX-8]  RLS lengkap semua tabel + storage policies
-- [FIX-9]  Urutan eksekusi aman (tidak ada UPDATE sebelum DROP)
-- [NEW-1]  Row-level audit log via tabel audit_logs
-- [NEW-2]  Storage bucket: product-images, receipts, documents
-- =====================================================================

-- =====================================================================
-- 0. SAFETY: Jalankan dalam satu transaksi
-- =====================================================================
BEGIN;

-- =====================================================================
-- 1. EXTENSIONS
-- =====================================================================
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE EXTENSION IF NOT EXISTS "pgcrypto";

-- =====================================================================
-- 2. DROP SEMUA ENUM TYPES (urutan aman)
-- =====================================================================
DROP TYPE IF EXISTS public.action_type        CASCADE;
DROP TYPE IF EXISTS public.movement_type      CASCADE;
DROP TYPE IF EXISTS public.reference_type     CASCADE;
DROP TYPE IF EXISTS public.order_status       CASCADE;
DROP TYPE IF EXISTS public.payment_method     CASCADE;
DROP TYPE IF EXISTS public.transaction_status CASCADE;
DROP TYPE IF EXISTS public.shift_status       CASCADE;
DROP TYPE IF EXISTS public.debt_status        CASCADE;
DROP TYPE IF EXISTS public.report_period      CASCADE;
DROP TYPE IF EXISTS public.user_role          CASCADE;
DROP TYPE IF EXISTS public.unit_type          CASCADE;

-- =====================================================================
-- 3. ENUM TYPES
-- =====================================================================
CREATE TYPE public.user_role AS ENUM (
    'owner', 'manager', 'cashier'
);

CREATE TYPE public.action_type AS ENUM (
    'open_shift', 'close_shift',
    'open_drawer', 'print_receipt',
    'void_transaction', 'discount_override',
    'refund', 'price_override', 'login', 'logout'
);

CREATE TYPE public.movement_type AS ENUM (
    'purchase',         -- stok masuk dari PO
    'sale',             -- stok keluar dari penjualan
    'adjustment_in',    -- koreksi tambah (opname)
    'adjustment_out',   -- koreksi kurang (opname)
    'initial_stock',    -- stok awal
    'return_in',        -- retur dari pembeli
    'return_out',       -- retur ke supplier
    'transfer_in',      -- pindah lokasi masuk
    'transfer_out',     -- pindah lokasi keluar
    'spoilage',         -- barang rusak/kadaluarsa
    'void'              -- void transaksi
);

CREATE TYPE public.reference_type AS ENUM (
    'transaction',
    'purchase_order',
    'adjustment',
    'return',
    'initial',
    'transfer',
    'void'
);

CREATE TYPE public.order_status AS ENUM (
    'draft', 'ordered', 'partial', 'received', 'cancelled'
);

CREATE TYPE public.payment_method AS ENUM (
    'cash', 'card', 'qris', 'transfer', 'debt', 'mixed'
);

CREATE TYPE public.transaction_status AS ENUM (
    'pending', 'completed', 'voided', 'refunded'
);

CREATE TYPE public.shift_status AS ENUM (
    'open', 'closed'
);

CREATE TYPE public.debt_status AS ENUM (
    'unpaid', 'partial', 'paid'
);

CREATE TYPE public.report_period AS ENUM (
    'daily', 'weekly', 'monthly', 'yearly'
);

CREATE TYPE public.unit_type AS ENUM (
    'piece', 'weight', 'volume', 'length', 'area', 'custom'
);

-- =====================================================================
-- 4. TABLES
-- =====================================================================

-- -----------------------------------------------------------------------
-- 4.1 profiles (extends auth.users)
-- -----------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS public.profiles (
                                               id           UUID        PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
    full_name    TEXT        NOT NULL DEFAULT '',
    role         public.user_role NOT NULL DEFAULT 'cashier',
    phone        TEXT,
    avatar_url   TEXT,
    is_active    BOOLEAN     NOT NULL DEFAULT true,
    pin_hash     TEXT,                        -- bcrypt hash of 6-digit PIN
    created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at   TIMESTAMPTZ NOT NULL DEFAULT NOW()
    );

-- -----------------------------------------------------------------------
-- 4.2 categories
-- -----------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS public.categories (
                                                 id          UUID    PRIMARY KEY DEFAULT gen_random_uuid(),
    name        TEXT    NOT NULL,
    description TEXT,
    color       TEXT    DEFAULT '#6B7280',
    icon        TEXT,
    is_active   BOOLEAN NOT NULL DEFAULT true,
    sort_order  INTEGER NOT NULL DEFAULT 0,
    created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    CONSTRAINT categories_name_unique UNIQUE (name)
    );

-- -----------------------------------------------------------------------
-- 4.3 units
-- -----------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS public.units (
                                            id           UUID           PRIMARY KEY DEFAULT gen_random_uuid(),
    name         TEXT           NOT NULL,
    abbreviation TEXT           NOT NULL,
    unit_type    public.unit_type NOT NULL DEFAULT 'piece',
    is_active    BOOLEAN        NOT NULL DEFAULT true,
    created_at   TIMESTAMPTZ    NOT NULL DEFAULT NOW(),
    CONSTRAINT units_name_unique UNIQUE (name),
    CONSTRAINT units_abbr_unique UNIQUE (abbreviation)
    );

-- -----------------------------------------------------------------------
-- 4.4 suppliers
-- -----------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS public.suppliers (
                                                id           UUID    PRIMARY KEY DEFAULT gen_random_uuid(),
    name         TEXT    NOT NULL,
    contact_name TEXT,
    phone        TEXT,
    email        TEXT,
    address      TEXT,
    tax_number   TEXT,
    is_active    BOOLEAN NOT NULL DEFAULT true,
    notes        TEXT,
    created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at   TIMESTAMPTZ NOT NULL DEFAULT NOW()
    );

-- -----------------------------------------------------------------------
-- 4.5 customers
-- -----------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS public.customers (
                                                id             UUID    PRIMARY KEY DEFAULT gen_random_uuid(),
    name           TEXT    NOT NULL,
    phone          TEXT,
    email          TEXT,
    address        TEXT,
    total_debt     INTEGER NOT NULL DEFAULT 0 CHECK (total_debt >= 0),
    loyalty_points INTEGER NOT NULL DEFAULT 0 CHECK (loyalty_points >= 0),
    is_active      BOOLEAN NOT NULL DEFAULT true,
    notes          TEXT,
    created_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at     TIMESTAMPTZ NOT NULL DEFAULT NOW()
    );

-- -----------------------------------------------------------------------
-- 4.6 products
-- -----------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS public.products (
                                               id                  UUID    PRIMARY KEY DEFAULT gen_random_uuid(),
    sku                 TEXT    NOT NULL,
    barcode             TEXT,
    name                TEXT    NOT NULL,
    description         TEXT,
    category_id         UUID    REFERENCES public.categories(id) ON DELETE SET NULL,
    unit_id             UUID    REFERENCES public.units(id) ON DELETE SET NULL,
    -- Harga
    cost_price          INTEGER NOT NULL DEFAULT 0 CHECK (cost_price >= 0),
    selling_price       INTEGER NOT NULL DEFAULT 0 CHECK (selling_price >= 0),
    min_selling_price   INTEGER NOT NULL DEFAULT 0 CHECK (min_selling_price >= 0),
    -- Stok
    stock               INTEGER NOT NULL DEFAULT 0,
    cached_stock        INTEGER NOT NULL DEFAULT 0,
    low_stock_threshold INTEGER NOT NULL DEFAULT 5,
    track_stock         BOOLEAN NOT NULL DEFAULT true,
    has_variants        BOOLEAN NOT NULL DEFAULT false,
    -- Meta
    image_url           TEXT,
    is_active           BOOLEAN NOT NULL DEFAULT true,
    is_featured         BOOLEAN NOT NULL DEFAULT false,
    tax_rate            NUMERIC(5,2) NOT NULL DEFAULT 0,
    created_by          UUID    REFERENCES auth.users(id),
    created_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    CONSTRAINT products_sku_unique UNIQUE (sku),
    CONSTRAINT products_price_check CHECK (min_selling_price <= selling_price)
    );

-- -----------------------------------------------------------------------
-- 4.7 product_variants
-- -----------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS public.product_variants (
                                                       id                 UUID    PRIMARY KEY DEFAULT gen_random_uuid(),
    product_id         UUID    NOT NULL REFERENCES public.products(id) ON DELETE CASCADE,
    sku                TEXT    NOT NULL,
    barcode            TEXT,
    name               TEXT    NOT NULL,  -- e.g. "Merah - L"
-- Atribut
    attributes         JSONB   NOT NULL DEFAULT '{}',  -- {"color":"Merah","size":"L"}
-- Harga — inherit dari produk jika inherit_cost_price=true
    inherit_cost_price BOOLEAN NOT NULL DEFAULT false,
    cost_price         INTEGER NOT NULL DEFAULT 0 CHECK (cost_price >= 0),
    selling_price      INTEGER NOT NULL DEFAULT 0 CHECK (selling_price >= 0),
    -- Stok
    cached_stock       INTEGER NOT NULL DEFAULT 0,
    low_stock_threshold INTEGER NOT NULL DEFAULT 5,
    -- Meta
    image_url          TEXT,
    is_active          BOOLEAN NOT NULL DEFAULT true,
    sort_order         INTEGER NOT NULL DEFAULT 0,
    created_at         TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at         TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    CONSTRAINT product_variants_sku_unique UNIQUE (sku)
    );

COMMENT ON COLUMN public.product_variants.inherit_cost_price IS
    'Jika true, cost_price diambil dari tabel products parent. '
    'Kolom cost_price di sini hanya dipakai saat inherit_cost_price = false.';

-- -----------------------------------------------------------------------
-- 4.8 shifts
-- -----------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS public.shifts (
                                             id              UUID               PRIMARY KEY DEFAULT gen_random_uuid(),
    cashier_id      UUID               NOT NULL REFERENCES auth.users(id),
    status          public.shift_status NOT NULL DEFAULT 'open',
    opening_cash    INTEGER            NOT NULL DEFAULT 0 CHECK (opening_cash >= 0),
    closing_cash    INTEGER,
    expected_cash   INTEGER,
    -- [FIX-2] GENERATED ALWAYS AS STORED — bukan DEFAULT
    cash_difference INTEGER GENERATED ALWAYS AS (
                                                    CASE WHEN closing_cash IS NOT NULL AND expected_cash IS NOT NULL
                                                    THEN closing_cash - expected_cash
                                                    ELSE NULL END
                                                ) STORED,
    notes           TEXT,
    opened_at       TIMESTAMPTZ        NOT NULL DEFAULT NOW(),
    closed_at       TIMESTAMPTZ,
    created_at      TIMESTAMPTZ        NOT NULL DEFAULT NOW(),
    updated_at      TIMESTAMPTZ        NOT NULL DEFAULT NOW()
    );

-- -----------------------------------------------------------------------
-- 4.9 cashier_actions
-- -----------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS public.cashier_actions (
                                                      id          UUID               PRIMARY KEY DEFAULT gen_random_uuid(),
    cashier_id  UUID               REFERENCES auth.users(id),
    shift_id    UUID               REFERENCES public.shifts(id),
    action_type public.action_type NOT NULL,
    metadata    JSONB              NOT NULL DEFAULT '{}',
    notes       TEXT,
    created_at  TIMESTAMPTZ        NOT NULL DEFAULT NOW()
    );

-- -----------------------------------------------------------------------
-- 4.10 transactions
-- -----------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS public.transactions (
                                                   id               UUID                     PRIMARY KEY DEFAULT gen_random_uuid(),
    transaction_code TEXT                     NOT NULL,
    shift_id         UUID                     REFERENCES public.shifts(id),
    cashier_id       UUID                     REFERENCES auth.users(id),
    customer_id      UUID                     REFERENCES public.customers(id) ON DELETE SET NULL,
    -- Status & Payment
    status           public.transaction_status NOT NULL DEFAULT 'pending',
    payment_method   public.payment_method    NOT NULL DEFAULT 'cash',
    -- Amounts (dalam satuan terkecil, misal sen atau rupiah bulat)
    subtotal         INTEGER NOT NULL DEFAULT 0 CHECK (subtotal >= 0),
    discount_amount  INTEGER NOT NULL DEFAULT 0 CHECK (discount_amount >= 0),
    tax_amount       INTEGER NOT NULL DEFAULT 0 CHECK (tax_amount >= 0),
    total_amount     INTEGER NOT NULL DEFAULT 0 CHECK (total_amount >= 0),
    paid_amount      INTEGER NOT NULL DEFAULT 0 CHECK (paid_amount >= 0),
    change_amount    INTEGER NOT NULL DEFAULT 0,
    debt_amount      INTEGER NOT NULL DEFAULT 0 CHECK (debt_amount >= 0),
    -- Metadata
    notes            TEXT,
    voided_by        UUID REFERENCES auth.users(id),
    voided_at        TIMESTAMPTZ,
    void_reason      TEXT,
    receipt_url      TEXT,
    created_at       TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at       TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    CONSTRAINT transactions_code_unique UNIQUE (transaction_code),
    CONSTRAINT transactions_total_check CHECK (
                                                  total_amount = subtotal - discount_amount + tax_amount
                                              )
    );

-- -----------------------------------------------------------------------
-- 4.11 transaction_items
-- -----------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS public.transaction_items (
                                                        id             UUID    PRIMARY KEY DEFAULT gen_random_uuid(),
    transaction_id UUID    NOT NULL REFERENCES public.transactions(id) ON DELETE CASCADE,
    product_id     UUID    NOT NULL REFERENCES public.products(id),
    variant_id     UUID    REFERENCES public.product_variants(id),
    -- Snapshot saat transaksi (harga bisa berubah)
    product_name   TEXT    NOT NULL,
    variant_name   TEXT,
    sku            TEXT    NOT NULL,
    -- Qty & Harga
    quantity       INTEGER NOT NULL CHECK (quantity > 0),
    unit_price     INTEGER NOT NULL CHECK (unit_price >= 0),
    cost_price     INTEGER NOT NULL DEFAULT 0 CHECK (cost_price >= 0),
    discount       INTEGER NOT NULL DEFAULT 0 CHECK (discount >= 0),
    total_price    INTEGER NOT NULL CHECK (total_price >= 0),
    -- Margin (computed sisi app, disimpan untuk laporan)
    gross_profit   INTEGER GENERATED ALWAYS AS (
                                                   total_price - (cost_price * quantity)
    ) STORED,
    created_at     TIMESTAMPTZ NOT NULL DEFAULT NOW()
    );

-- -----------------------------------------------------------------------
-- 4.12 inventory_movements
-- -----------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS public.inventory_movements (
                                                          id             UUID                  PRIMARY KEY DEFAULT gen_random_uuid(),
    product_id     UUID                  NOT NULL REFERENCES public.products(id) ON DELETE RESTRICT,
    variant_id     UUID                  REFERENCES public.product_variants(id) ON DELETE RESTRICT,
    movement_type  public.movement_type  NOT NULL,
    reference_type public.reference_type NOT NULL,  -- [FIX-5] pakai ENUM, bukan text
    reference_id   UUID,                            -- FK ke tabel relevan (nullable karena polymorphic)
-- Stok
    qty_before     INTEGER NOT NULL,
    qty_change     INTEGER NOT NULL,    -- positif = masuk, negatif = keluar
    qty_after      INTEGER NOT NULL,
    -- Harga saat gerakan terjadi
    unit_cost      INTEGER NOT NULL DEFAULT 0,
    total_cost     INTEGER GENERATED ALWAYS AS (
                                                   ABS(qty_change) * unit_cost
    ) STORED,
    -- Audit
    notes          TEXT,
    created_by     UUID REFERENCES auth.users(id),
    created_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    CONSTRAINT inventory_movements_qty_check CHECK (
                                                       qty_after = qty_before + qty_change
                                                   ),
    CONSTRAINT inventory_movements_qty_after_nn CHECK (qty_after >= 0)
    );

COMMENT ON TABLE public.inventory_movements IS
    'Immutable ledger. Jangan pernah UPDATE/DELETE baris di tabel ini. '
    'Stok produk = SUM(qty_change) untuk product_id tertentu.';

-- -----------------------------------------------------------------------
-- 4.13 purchase_orders
-- -----------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS public.purchase_orders (
                                                      id             UUID               PRIMARY KEY DEFAULT gen_random_uuid(),
    po_number      TEXT               NOT NULL,
    supplier_id    UUID               REFERENCES public.suppliers(id) ON DELETE SET NULL,
    status         public.order_status NOT NULL DEFAULT 'draft',
    -- Amounts
    subtotal       INTEGER NOT NULL DEFAULT 0 CHECK (subtotal >= 0),
    discount       INTEGER NOT NULL DEFAULT 0 CHECK (discount >= 0),
    tax_amount     INTEGER NOT NULL DEFAULT 0 CHECK (tax_amount >= 0),
    total_amount   INTEGER NOT NULL DEFAULT 0 CHECK (total_amount >= 0),
    paid_amount    INTEGER NOT NULL DEFAULT 0 CHECK (paid_amount >= 0),
    -- Dates
    order_date     DATE    NOT NULL DEFAULT CURRENT_DATE,
    expected_date  DATE,
    received_date  DATE,
    -- Meta
    notes          TEXT,
    created_by     UUID REFERENCES auth.users(id),
    created_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    CONSTRAINT purchase_orders_po_unique UNIQUE (po_number)
    );

-- -----------------------------------------------------------------------
-- 4.14 purchase_order_items
-- -----------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS public.purchase_order_items (
                                                           id                UUID    PRIMARY KEY DEFAULT gen_random_uuid(),
    purchase_order_id UUID    NOT NULL REFERENCES public.purchase_orders(id) ON DELETE CASCADE,
    product_id        UUID    NOT NULL REFERENCES public.products(id) ON DELETE RESTRICT,
    variant_id        UUID    REFERENCES public.product_variants(id),
    -- Snapshot
    product_name      TEXT    NOT NULL,
    sku               TEXT    NOT NULL,
    -- Qty & Harga
    ordered_qty       INTEGER NOT NULL CHECK (ordered_qty > 0),
    received_qty      INTEGER NOT NULL DEFAULT 0 CHECK (received_qty >= 0),
    unit_cost         INTEGER NOT NULL CHECK (unit_cost >= 0),
    total_cost        INTEGER GENERATED ALWAYS AS (received_qty * unit_cost) STORED,
    created_at        TIMESTAMPTZ NOT NULL DEFAULT NOW()
    );

-- -----------------------------------------------------------------------
-- 4.15 customer_debts
-- -----------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS public.customer_debts (
                                                     id             UUID               PRIMARY KEY DEFAULT gen_random_uuid(),
    customer_id    UUID               NOT NULL REFERENCES public.customers(id) ON DELETE RESTRICT,
    transaction_id UUID               REFERENCES public.transactions(id) ON DELETE SET NULL,
    amount         INTEGER            NOT NULL CHECK (amount > 0),
    paid_amount    INTEGER            NOT NULL DEFAULT 0 CHECK (paid_amount >= 0),
    -- [FIX-1] GENERATED ALWAYS AS STORED — bukan DEFAULT
    remaining      INTEGER GENERATED ALWAYS AS (amount - paid_amount) STORED,
    status         public.debt_status NOT NULL DEFAULT 'unpaid',
    due_date       DATE,
    notes          TEXT,
    created_by     UUID REFERENCES auth.users(id),
    created_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    CONSTRAINT customer_debts_paid_check CHECK (paid_amount <= amount)
    );

-- -----------------------------------------------------------------------
-- 4.16 debt_payments
-- -----------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS public.debt_payments (
                                                    id             UUID               PRIMARY KEY DEFAULT gen_random_uuid(),
    debt_id        UUID               NOT NULL REFERENCES public.customer_debts(id) ON DELETE RESTRICT,
    customer_id    UUID               NOT NULL REFERENCES public.customers(id),
    amount         INTEGER            NOT NULL CHECK (amount > 0),
    payment_method public.payment_method NOT NULL DEFAULT 'cash',
    received_by    UUID               REFERENCES auth.users(id),
    notes          TEXT,
    created_at     TIMESTAMPTZ        NOT NULL DEFAULT NOW()
    );

-- -----------------------------------------------------------------------
-- 4.17 daily_reports
-- -----------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS public.daily_reports (
                                                    id                  UUID    PRIMARY KEY DEFAULT gen_random_uuid(),
    report_date         DATE    NOT NULL,
    -- Penjualan
    total_transactions  INTEGER NOT NULL DEFAULT 0,
    total_revenue       INTEGER NOT NULL DEFAULT 0,
    total_discount      INTEGER NOT NULL DEFAULT 0,
    total_tax           INTEGER NOT NULL DEFAULT 0,
    gross_profit        INTEGER NOT NULL DEFAULT 0,
    -- Inventori
    total_stock_in      INTEGER NOT NULL DEFAULT 0,
    total_stock_out     INTEGER NOT NULL DEFAULT 0,
    -- Hutang
    new_debts           INTEGER NOT NULL DEFAULT 0,
    debt_payments       INTEGER NOT NULL DEFAULT 0,
    -- Meta
    generated_by        UUID REFERENCES auth.users(id),
    notes               TEXT,
    created_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    CONSTRAINT daily_reports_date_unique UNIQUE (report_date)
    );

-- -----------------------------------------------------------------------
-- 4.18 audit_logs [NEW-1]
-- -----------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS public.audit_logs (
                                                 id          UUID    PRIMARY KEY DEFAULT gen_random_uuid(),
    table_name  TEXT    NOT NULL,
    record_id   UUID    NOT NULL,
    action      TEXT    NOT NULL CHECK (action IN ('INSERT', 'UPDATE', 'DELETE')),
    old_data    JSONB,
    new_data    JSONB,
    changed_by  UUID    REFERENCES auth.users(id),
    changed_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    ip_address  INET,
    user_agent  TEXT
    );

-- =====================================================================
-- 5. INDEXES
-- =====================================================================

-- profiles
CREATE INDEX IF NOT EXISTS idx_profiles_role ON public.profiles(role);

-- products
CREATE INDEX IF NOT EXISTS idx_products_sku         ON public.products(sku);
CREATE INDEX IF NOT EXISTS idx_products_barcode      ON public.products(barcode) WHERE barcode IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_products_category     ON public.products(category_id);
CREATE INDEX IF NOT EXISTS idx_products_is_active    ON public.products(is_active);
CREATE INDEX IF NOT EXISTS idx_products_name_search  ON public.products USING GIN(to_tsvector('indonesian', name));
CREATE INDEX IF NOT EXISTS idx_products_cached_stock ON public.products(cached_stock) WHERE track_stock = true;

-- product_variants
CREATE INDEX IF NOT EXISTS idx_variants_product_id  ON public.product_variants(product_id);
CREATE INDEX IF NOT EXISTS idx_variants_sku         ON public.product_variants(sku);
CREATE INDEX IF NOT EXISTS idx_variants_barcode     ON public.product_variants(barcode) WHERE barcode IS NOT NULL;

-- shifts
CREATE INDEX IF NOT EXISTS idx_shifts_cashier       ON public.shifts(cashier_id);
CREATE INDEX IF NOT EXISTS idx_shifts_status        ON public.shifts(status);
CREATE INDEX IF NOT EXISTS idx_shifts_opened_at     ON public.shifts(opened_at DESC);

-- cashier_actions
CREATE INDEX IF NOT EXISTS idx_cashier_actions_shift    ON public.cashier_actions(shift_id);
CREATE INDEX IF NOT EXISTS idx_cashier_actions_cashier  ON public.cashier_actions(cashier_id);
CREATE INDEX IF NOT EXISTS idx_cashier_actions_type     ON public.cashier_actions(action_type);
CREATE INDEX IF NOT EXISTS idx_cashier_actions_time     ON public.cashier_actions(created_at DESC);

-- transactions
CREATE INDEX IF NOT EXISTS idx_transactions_shift       ON public.transactions(shift_id);
CREATE INDEX IF NOT EXISTS idx_transactions_cashier     ON public.transactions(cashier_id);
CREATE INDEX IF NOT EXISTS idx_transactions_customer    ON public.transactions(customer_id);
CREATE INDEX IF NOT EXISTS idx_transactions_status      ON public.transactions(status);
CREATE INDEX IF NOT EXISTS idx_transactions_code        ON public.transactions(transaction_code);
CREATE INDEX IF NOT EXISTS idx_transactions_created_at  ON public.transactions(created_at DESC);
CREATE INDEX IF NOT EXISTS idx_transactions_date        ON public.transactions(DATE(created_at));

-- transaction_items
CREATE INDEX IF NOT EXISTS idx_txn_items_transaction  ON public.transaction_items(transaction_id);
CREATE INDEX IF NOT EXISTS idx_txn_items_product      ON public.transaction_items(product_id);
CREATE INDEX IF NOT EXISTS idx_txn_items_variant      ON public.transaction_items(variant_id);

-- inventory_movements
CREATE INDEX IF NOT EXISTS idx_inv_mov_product         ON public.inventory_movements(product_id);
CREATE INDEX IF NOT EXISTS idx_inv_mov_variant         ON public.inventory_movements(variant_id);
CREATE INDEX IF NOT EXISTS idx_inv_mov_type            ON public.inventory_movements(movement_type);
CREATE INDEX IF NOT EXISTS idx_inv_mov_reference       ON public.inventory_movements(reference_type, reference_id);
CREATE INDEX IF NOT EXISTS idx_inv_mov_created_at      ON public.inventory_movements(created_at DESC);
CREATE INDEX IF NOT EXISTS idx_inv_mov_product_time    ON public.inventory_movements(product_id, created_at DESC);

-- purchase_orders
CREATE INDEX IF NOT EXISTS idx_po_supplier   ON public.purchase_orders(supplier_id);
CREATE INDEX IF NOT EXISTS idx_po_status     ON public.purchase_orders(status);
CREATE INDEX IF NOT EXISTS idx_po_date       ON public.purchase_orders(order_date DESC);
CREATE INDEX IF NOT EXISTS idx_po_number     ON public.purchase_orders(po_number);

-- purchase_order_items
CREATE INDEX IF NOT EXISTS idx_poi_po        ON public.purchase_order_items(purchase_order_id);
CREATE INDEX IF NOT EXISTS idx_poi_product   ON public.purchase_order_items(product_id);

-- customer_debts
CREATE INDEX IF NOT EXISTS idx_debts_customer   ON public.customer_debts(customer_id);
CREATE INDEX IF NOT EXISTS idx_debts_status     ON public.customer_debts(status);
CREATE INDEX IF NOT EXISTS idx_debts_due_date   ON public.customer_debts(due_date) WHERE status != 'paid';

-- debt_payments
CREATE INDEX IF NOT EXISTS idx_debt_payments_debt      ON public.debt_payments(debt_id);
CREATE INDEX IF NOT EXISTS idx_debt_payments_customer  ON public.debt_payments(customer_id);
CREATE INDEX IF NOT EXISTS idx_debt_payments_time      ON public.debt_payments(created_at DESC);

-- daily_reports
CREATE INDEX IF NOT EXISTS idx_daily_reports_date ON public.daily_reports(report_date DESC);

-- audit_logs
CREATE INDEX IF NOT EXISTS idx_audit_logs_table   ON public.audit_logs(table_name, record_id);
CREATE INDEX IF NOT EXISTS idx_audit_logs_user    ON public.audit_logs(changed_by);
CREATE INDEX IF NOT EXISTS idx_audit_logs_time    ON public.audit_logs(changed_at DESC);

-- =====================================================================
-- 6. FUNCTIONS
-- =====================================================================

-- -----------------------------------------------------------------------
-- 6.1 updated_at auto-update
-- -----------------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fn_set_updated_at()
RETURNS TRIGGER
LANGUAGE plpgsql
AS $$
BEGIN
    NEW.updated_at := NOW();
RETURN NEW;
END;
$$;

-- -----------------------------------------------------------------------
-- 6.2 Auto-create profile saat user baru di auth.users
-- -----------------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fn_handle_new_user()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, auth
AS $$
BEGIN
INSERT INTO public.profiles (id, full_name, role)
VALUES (
           NEW.id,
           COALESCE(NEW.raw_user_meta_data->>'full_name', NEW.email, ''),
           COALESCE(
                   (NEW.raw_user_meta_data->>'role')::public.user_role,
                   'cashier'
           )
       )
    ON CONFLICT (id) DO NOTHING;
RETURN NEW;
END;
$$;

-- -----------------------------------------------------------------------
-- 6.3 Sync stock dari inventory_movements (LEDGER approach)
-- [FIX-3] Tidak ada blokir langsung UPDATE stock — cukup lewat ledger
-- Fungsi ini dipakai trigger AFTER INSERT ON inventory_movements
-- -----------------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fn_sync_stock_from_movement()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
    -- Update stock produk berdasarkan qty_after dari gerakan terakhir
UPDATE public.products
SET
    stock        = NEW.qty_after,
    cached_stock = NEW.qty_after,
    updated_at   = NOW()
WHERE id = NEW.product_id;

-- Update cached_stock varian jika ada
IF NEW.variant_id IS NOT NULL THEN
UPDATE public.product_variants
SET
    cached_stock = NEW.qty_after,
    updated_at   = NOW()
WHERE id = NEW.variant_id;
END IF;

RETURN NEW;
END;
$$;

-- -----------------------------------------------------------------------
-- 6.4 Validasi stok tidak boleh negatif sebelum movement diinsert
-- -----------------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fn_validate_stock_movement()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
v_current_stock INTEGER;
BEGIN
    -- Ambil stok terkini dari ledger (bukan kolom cached, lebih akurat)
SELECT COALESCE(SUM(qty_change), 0)
INTO v_current_stock
FROM public.inventory_movements
WHERE product_id = NEW.product_id
  AND (NEW.variant_id IS NULL OR variant_id = NEW.variant_id);

-- Hitung qty_before yang benar
NEW.qty_before := v_current_stock;
    NEW.qty_after  := v_current_stock + NEW.qty_change;

    -- Tolak jika hasil negatif
    IF NEW.qty_after < 0 THEN
        RAISE EXCEPTION
            'Stok tidak cukup untuk produk %. Stok saat ini: %, perubahan: %',
            NEW.product_id, v_current_stock, NEW.qty_change
            USING ERRCODE = 'check_violation';
END IF;

RETURN NEW;
END;
$$;

-- -----------------------------------------------------------------------
-- 6.5 Catat stok awal (initial_stock movement)
-- [FIX-7] Fallback ke service_role untuk migration/seed
-- -----------------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fn_record_initial_stock(
    p_product_id  UUID,
    p_variant_id  UUID,
    p_qty         INTEGER,
    p_unit_cost   INTEGER DEFAULT 0,
    p_notes       TEXT    DEFAULT 'Stok awal'
)
RETURNS UUID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, auth
AS $$
DECLARE
v_user_id UUID;
    v_movement_id UUID;
BEGIN
    -- Ambil user_id; null untuk service_role (migration/seed) — diizinkan
    v_user_id := auth.uid();

    -- Cek jika sudah ada initial_stock untuk produk ini
    IF EXISTS (
        SELECT 1 FROM public.inventory_movements
        WHERE product_id    = p_product_id
          AND movement_type = 'initial_stock'
          AND (p_variant_id IS NULL OR variant_id = p_variant_id)
    ) THEN
        RAISE EXCEPTION 'Stok awal sudah dicatat untuk produk ini'
            USING ERRCODE = 'unique_violation';
END IF;

    IF p_qty < 0 THEN
        RAISE EXCEPTION 'Stok awal tidak boleh negatif'
            USING ERRCODE = 'check_violation';
END IF;

INSERT INTO public.inventory_movements (
    product_id, variant_id, movement_type, reference_type,
    qty_before, qty_change, qty_after,
    unit_cost, notes, created_by
) VALUES (
             p_product_id, p_variant_id, 'initial_stock', 'initial',
             0, p_qty, p_qty,
             p_unit_cost, p_notes, v_user_id
         )
    RETURNING id INTO v_movement_id;

RETURN v_movement_id;
END;
$$;

-- -----------------------------------------------------------------------
-- 6.6 Proses transaksi — kurangi stok & buat movement
-- -----------------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fn_process_sale_stock(
    p_transaction_id UUID
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
v_item RECORD;
BEGIN
FOR v_item IN
SELECT ti.product_id, ti.variant_id, ti.quantity, ti.cost_price
FROM public.transaction_items ti
WHERE ti.transaction_id = p_transaction_id
    LOOP
INSERT INTO public.inventory_movements (
    product_id, variant_id, movement_type, reference_type, reference_id,
    qty_before, qty_change, qty_after,
    unit_cost, notes, created_by
)
SELECT
    v_item.product_id,
    v_item.variant_id,
    'sale',
    'transaction',
    p_transaction_id,
    COALESCE(SUM(qty_change), 0),
    -v_item.quantity,
    COALESCE(SUM(qty_change), 0) - v_item.quantity,
    v_item.cost_price,
    'Penjualan: ' || p_transaction_id,
    auth.uid()
FROM public.inventory_movements
WHERE product_id = v_item.product_id
  AND (v_item.variant_id IS NULL OR variant_id = v_item.variant_id);
END LOOP;
END;
$$;

-- -----------------------------------------------------------------------
-- 6.7 Proses penerimaan Purchase Order — tambah stok
-- -----------------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fn_process_po_receipt(
    p_po_id UUID
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
v_item RECORD;
BEGIN
FOR v_item IN
SELECT poi.product_id, poi.variant_id, poi.received_qty, poi.unit_cost
FROM public.purchase_order_items poi
WHERE poi.purchase_order_id = p_po_id
  AND poi.received_qty > 0
    LOOP
INSERT INTO public.inventory_movements (
    product_id, variant_id, movement_type, reference_type, reference_id,
    qty_before, qty_change, qty_after,
    unit_cost, notes, created_by
)
SELECT
    v_item.product_id,
    v_item.variant_id,
    'purchase',
    'purchase_order',
    p_po_id,
    COALESCE(SUM(qty_change), 0),
    v_item.received_qty,
    COALESCE(SUM(qty_change), 0) + v_item.received_qty,
    v_item.unit_cost,
    'Penerimaan PO: ' || p_po_id,
    auth.uid()
FROM public.inventory_movements
WHERE product_id = v_item.product_id
  AND (v_item.variant_id IS NULL OR variant_id = v_item.variant_id);
END LOOP;

    -- Update status PO
UPDATE public.purchase_orders
SET
    status        = 'received',
    received_date = CURRENT_DATE,
    updated_at    = NOW()
WHERE id = p_po_id;
END;
$$;

-- -----------------------------------------------------------------------
-- 6.8 Proses debt payment — update paid_amount & status
-- -----------------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fn_apply_debt_payment()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
v_debt RECORD;
BEGIN
SELECT * INTO v_debt
FROM public.customer_debts
WHERE id = NEW.debt_id
    FOR UPDATE;  -- lock baris untuk mencegah race condition

-- Cek tidak melebihi sisa hutang
IF NEW.amount > (v_debt.amount - v_debt.paid_amount) THEN
        RAISE EXCEPTION
            'Pembayaran (%) melebihi sisa hutang (%)',
            NEW.amount, (v_debt.amount - v_debt.paid_amount)
            USING ERRCODE = 'check_violation';
END IF;

    -- Update hutang
UPDATE public.customer_debts
SET
    paid_amount = paid_amount + NEW.amount,
    status = CASE
                 WHEN paid_amount + NEW.amount >= amount THEN 'paid'
                 WHEN paid_amount + NEW.amount > 0       THEN 'partial'
                 ELSE 'unpaid'
        END,
    updated_at = NOW()
WHERE id = NEW.debt_id;

-- Update total_debt customer
UPDATE public.customers
SET
    total_debt = GREATEST(0, total_debt - NEW.amount),
    updated_at = NOW()
WHERE id = NEW.customer_id;

RETURN NEW;
END;
$$;

-- -----------------------------------------------------------------------
-- 6.9 Auto-generate transaction_code
-- -----------------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fn_generate_transaction_code()
RETURNS TRIGGER
LANGUAGE plpgsql
AS $$
DECLARE
v_code TEXT;
    v_counter INTEGER;
BEGIN
    IF NEW.transaction_code IS NOT NULL AND NEW.transaction_code != '' THEN
        RETURN NEW;
END IF;

    -- Format: TRX-YYYYMMDD-XXXX
SELECT COUNT(*) + 1 INTO v_counter
FROM public.transactions
WHERE DATE(created_at) = CURRENT_DATE;

v_code := 'TRX-' || TO_CHAR(NOW(), 'YYYYMMDD') || '-' || LPAD(v_counter::TEXT, 4, '0');
    NEW.transaction_code := v_code;
RETURN NEW;
END;
$$;

-- -----------------------------------------------------------------------
-- 6.10 Auto-generate PO number
-- -----------------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fn_generate_po_number()
RETURNS TRIGGER
LANGUAGE plpgsql
AS $$
DECLARE
v_code TEXT;
    v_counter INTEGER;
BEGIN
    IF NEW.po_number IS NOT NULL AND NEW.po_number != '' THEN
        RETURN NEW;
END IF;

SELECT COUNT(*) + 1 INTO v_counter
FROM public.purchase_orders
WHERE DATE_TRUNC('month', order_date) = DATE_TRUNC('month', CURRENT_DATE);

v_code := 'PO-' || TO_CHAR(NOW(), 'YYYYMM') || '-' || LPAD(v_counter::TEXT, 4, '0');
    NEW.po_number := v_code;
RETURN NEW;
END;
$$;

-- -----------------------------------------------------------------------
-- 6.11 Update daily_report saat transaksi selesai
-- -----------------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fn_update_daily_report()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
    -- Hanya proses jika status berubah ke 'completed'
    IF (TG_OP = 'UPDATE' AND NEW.status = 'completed' AND OLD.status != 'completed') OR
       (TG_OP = 'INSERT' AND NEW.status = 'completed') THEN

        INSERT INTO public.daily_reports (
            report_date, total_transactions, total_revenue,
            total_discount, total_tax, gross_profit
        ) VALUES (
            DATE(NEW.created_at), 1, NEW.total_amount,
            NEW.discount_amount, NEW.tax_amount,
            NEW.total_amount - NEW.discount_amount - COALESCE((
                SELECT SUM(cost_price * quantity) FROM public.transaction_items
                WHERE transaction_id = NEW.id
            ), 0)
        )
        ON CONFLICT (report_date) DO UPDATE SET
    total_transactions = public.daily_reports.total_transactions + 1,
                                                total_revenue      = public.daily_reports.total_revenue + EXCLUDED.total_revenue,
                                                total_discount     = public.daily_reports.total_discount + EXCLUDED.total_discount,
                                                total_tax          = public.daily_reports.total_tax + EXCLUDED.total_tax,
                                                gross_profit       = public.daily_reports.gross_profit + EXCLUDED.gross_profit,
                                                updated_at         = NOW();
END IF;

    -- Handle void: kurangi daily report
    IF TG_OP = 'UPDATE' AND NEW.status = 'voided' AND OLD.status = 'completed' THEN
UPDATE public.daily_reports
SET
    total_transactions = GREATEST(0, total_transactions - 1),
    total_revenue      = GREATEST(0, total_revenue - OLD.total_amount),
    total_discount     = GREATEST(0, total_discount - OLD.discount_amount),
    updated_at         = NOW()
WHERE report_date = DATE(OLD.created_at);
END IF;

RETURN NEW;
END;
$$;

-- -----------------------------------------------------------------------
-- 6.12 Generic audit log
-- -----------------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fn_audit_log()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, auth
AS $$
BEGIN
INSERT INTO public.audit_logs (
    table_name, record_id, action,
    old_data, new_data, changed_by
)
VALUES (
           TG_TABLE_NAME,
           CASE TG_OP WHEN 'DELETE' THEN OLD.id ELSE NEW.id END,
           TG_OP,
           CASE TG_OP WHEN 'INSERT' THEN NULL ELSE to_jsonb(OLD) END,
           CASE TG_OP WHEN 'DELETE' THEN NULL ELSE to_jsonb(NEW) END,
           auth.uid()
       );
RETURN NULL;  -- AFTER trigger, nilai return diabaikan
END;
$$;

-- -----------------------------------------------------------------------
-- 6.13 Sync inherit_cost_price — auto update cost dari parent
-- -----------------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fn_sync_variant_cost()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
    -- Jika variant inherit_cost_price = true, ambil dari parent
    IF NEW.inherit_cost_price = true THEN
        NEW.cost_price := (
            SELECT cost_price FROM public.products WHERE id = NEW.product_id
        );
END IF;
RETURN NEW;
END;
$$;

-- -----------------------------------------------------------------------
-- 6.14 Jaga integritas: qty_before di inventory_movements harus konsisten
-- -----------------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fn_lock_inventory_movements()
RETURNS TRIGGER
LANGUAGE plpgsql
AS $$
BEGIN
    IF TG_OP = 'UPDATE' OR TG_OP = 'DELETE' THEN
        RAISE EXCEPTION
            'Ledger inventory_movements bersifat immutable. '
            'Gunakan movement baru (adjustment/void) untuk koreksi.'
            USING ERRCODE = 'restrict_violation';
END IF;
RETURN OLD;
END;
$$;

-- -----------------------------------------------------------------------
-- 6.15 Close shift — hitung expected_cash otomatis
-- -----------------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fn_close_shift(
    p_shift_id    UUID,
    p_closing_cash INTEGER,
    p_notes        TEXT DEFAULT NULL
)
RETURNS public.shifts
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
v_expected INTEGER;
    v_shift    public.shifts;
BEGIN
    -- Hitung expected: opening_cash + semua transaksi cash di shift ini
SELECT
    s.opening_cash + COALESCE(SUM(
                                      CASE t.payment_method
                                          WHEN 'cash' THEN t.paid_amount - t.change_amount
                                          ELSE 0
                                          END
                              ), 0)
INTO v_expected
FROM public.shifts s
         LEFT JOIN public.transactions t
                   ON t.shift_id = s.id AND t.status = 'completed'
WHERE s.id = p_shift_id
GROUP BY s.opening_cash;

UPDATE public.shifts
SET
    status        = 'closed',
    closing_cash  = p_closing_cash,
    expected_cash = v_expected,
    closed_at     = NOW(),
    notes         = COALESCE(p_notes, notes),
    updated_at    = NOW()
WHERE id = p_shift_id
    RETURNING * INTO v_shift;

RETURN v_shift;
END;
$$;

