    BEFORE UPDATE ON public.profiles
                      FOR EACH ROW EXECUTE FUNCTION public.fn_set_updated_at();

CREATE OR REPLACE TRIGGER trg_categories_updated_at
    BEFORE UPDATE ON public.categories
                      FOR EACH ROW EXECUTE FUNCTION public.fn_set_updated_at();

CREATE OR REPLACE TRIGGER trg_suppliers_updated_at
    BEFORE UPDATE ON public.suppliers
                      FOR EACH ROW EXECUTE FUNCTION public.fn_set_updated_at();

CREATE OR REPLACE TRIGGER trg_customers_updated_at
    BEFORE UPDATE ON public.customers
                      FOR EACH ROW EXECUTE FUNCTION public.fn_set_updated_at();

CREATE OR REPLACE TRIGGER trg_products_updated_at
    BEFORE UPDATE ON public.products
                      FOR EACH ROW EXECUTE FUNCTION public.fn_set_updated_at();

CREATE OR REPLACE TRIGGER trg_variants_updated_at
    BEFORE UPDATE ON public.product_variants
                      FOR EACH ROW EXECUTE FUNCTION public.fn_set_updated_at();

CREATE OR REPLACE TRIGGER trg_shifts_updated_at
    BEFORE UPDATE ON public.shifts
                      FOR EACH ROW EXECUTE FUNCTION public.fn_set_updated_at();

CREATE OR REPLACE TRIGGER trg_transactions_updated_at
    BEFORE UPDATE ON public.transactions
                      FOR EACH ROW EXECUTE FUNCTION public.fn_set_updated_at();

CREATE OR REPLACE TRIGGER trg_po_updated_at
    BEFORE UPDATE ON public.purchase_orders
                      FOR EACH ROW EXECUTE FUNCTION public.fn_set_updated_at();

CREATE OR REPLACE TRIGGER trg_debts_updated_at
    BEFORE UPDATE ON public.customer_debts
                      FOR EACH ROW EXECUTE FUNCTION public.fn_set_updated_at();

CREATE OR REPLACE TRIGGER trg_daily_reports_updated_at
    BEFORE UPDATE ON public.daily_reports
                      FOR EACH ROW EXECUTE FUNCTION public.fn_set_updated_at();

-- -----------------------------------------------------------------------
-- 7.2 Auto-create profile
-- -----------------------------------------------------------------------
DROP TRIGGER IF EXISTS trg_on_auth_user_created ON auth.users;
CREATE TRIGGER trg_on_auth_user_created
    AFTER INSERT ON auth.users
    FOR EACH ROW EXECUTE FUNCTION public.fn_handle_new_user();

-- -----------------------------------------------------------------------
-- 7.3 Transaction code generator
-- -----------------------------------------------------------------------
CREATE OR REPLACE TRIGGER trg_generate_txn_code
    BEFORE INSERT ON public.transactions
    FOR EACH ROW EXECUTE FUNCTION public.fn_generate_transaction_code();

-- -----------------------------------------------------------------------
-- 7.4 PO number generator
-- -----------------------------------------------------------------------
CREATE OR REPLACE TRIGGER trg_generate_po_number
    BEFORE INSERT ON public.purchase_orders
    FOR EACH ROW EXECUTE FUNCTION public.fn_generate_po_number();

-- -----------------------------------------------------------------------
-- 7.5 Validasi stok BEFORE INSERT inventory_movements
-- [FIX-3] Ini ganti seluruh approach "block + sync" yang konflik
-- -----------------------------------------------------------------------
CREATE OR REPLACE TRIGGER trg_validate_stock_movement
    BEFORE INSERT ON public.inventory_movements
    FOR EACH ROW EXECUTE FUNCTION public.fn_validate_stock_movement();

-- -----------------------------------------------------------------------
-- 7.6 Sync stock AFTER INSERT inventory_movements
-- -----------------------------------------------------------------------
CREATE OR REPLACE TRIGGER trg_sync_stock_from_movement
    AFTER INSERT ON public.inventory_movements
    FOR EACH ROW EXECUTE FUNCTION public.fn_sync_stock_from_movement();

-- -----------------------------------------------------------------------
-- 7.7 Lock inventory_movements (immutable ledger)
-- -----------------------------------------------------------------------
CREATE OR REPLACE TRIGGER trg_lock_inventory_movements
    BEFORE UPDATE OR DELETE ON public.inventory_movements
    FOR EACH ROW EXECUTE FUNCTION public.fn_lock_inventory_movements();

-- -----------------------------------------------------------------------
-- 7.8 Debt payment processor
-- -----------------------------------------------------------------------
CREATE OR REPLACE TRIGGER trg_apply_debt_payment
    AFTER INSERT ON public.debt_payments
    FOR EACH ROW EXECUTE FUNCTION public.fn_apply_debt_payment();

-- -----------------------------------------------------------------------
-- 7.9 Daily report updater
-- -----------------------------------------------------------------------
CREATE OR REPLACE TRIGGER trg_update_daily_report
    AFTER INSERT OR UPDATE OF status ON public.transactions
    FOR EACH ROW EXECUTE FUNCTION public.fn_update_daily_report();

-- -----------------------------------------------------------------------
-- 7.10 Variant cost sync
-- -----------------------------------------------------------------------
CREATE OR REPLACE TRIGGER trg_sync_variant_cost
    BEFORE INSERT OR UPDATE OF inherit_cost_price, cost_price ON public.product_variants
    FOR EACH ROW EXECUTE FUNCTION public.fn_sync_variant_cost();

-- -----------------------------------------------------------------------
-- 7.11 Audit logs — tabel sensitif saja (jangan semua, terlalu noisy)
-- -----------------------------------------------------------------------
CREATE OR REPLACE TRIGGER trg_audit_transactions
    AFTER INSERT OR UPDATE OR DELETE ON public.transactions
    FOR EACH ROW EXECUTE FUNCTION public.fn_audit_log();

CREATE OR REPLACE TRIGGER trg_audit_customer_debts
    AFTER INSERT OR UPDATE OR DELETE ON public.customer_debts
    FOR EACH ROW EXECUTE FUNCTION public.fn_audit_log();

CREATE OR REPLACE TRIGGER trg_audit_products
    AFTER INSERT OR UPDATE OR DELETE ON public.products
    FOR EACH ROW EXECUTE FUNCTION public.fn_audit_log();

CREATE OR REPLACE TRIGGER trg_audit_shifts
    AFTER INSERT OR UPDATE OR DELETE ON public.shifts
    FOR EACH ROW EXECUTE FUNCTION public.fn_audit_log();

