-- -----------------------------------------------------------------------
-- Helper: ambil role dari profiles (digunakan di policy)
-- -----------------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fn_get_user_role()
RETURNS public.user_role
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public, auth
AS $$
SELECT role FROM public.profiles WHERE id = auth.uid();
$$;

CREATE OR REPLACE FUNCTION public.fn_is_owner_or_manager()
RETURNS BOOLEAN
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
SELECT fn_get_user_role() IN ('owner', 'manager');
$$;

CREATE OR REPLACE FUNCTION public.fn_is_owner()
RETURNS BOOLEAN
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
SELECT fn_get_user_role() = 'owner';
$$;

-- -----------------------------------------------------------------------
-- 8.1 profiles
-- -----------------------------------------------------------------------
DROP POLICY IF EXISTS "profiles_select_own"   ON public.profiles;
DROP POLICY IF EXISTS "profiles_select_all"   ON public.profiles;
DROP POLICY IF EXISTS "profiles_update_own"   ON public.profiles;
DROP POLICY IF EXISTS "profiles_update_all"   ON public.profiles;
DROP POLICY IF EXISTS "profiles_insert"       ON public.profiles;

-- Semua user bisa lihat semua profile (untuk tampilan nama kasir dsb)
CREATE POLICY "profiles_select_all"
    ON public.profiles FOR SELECT
                                                               TO authenticated
                                                               USING (true);

-- Update diri sendiri, atau owner/manager update siapa saja
CREATE POLICY "profiles_update_own"
    ON public.profiles FOR UPDATE
                                      TO authenticated
                                      USING (id = auth.uid() OR public.fn_is_owner_or_manager())
                           WITH CHECK (id = auth.uid() OR public.fn_is_owner_or_manager());

-- Insert: hanya lewat service_role (trigger auth) atau owner
CREATE POLICY "profiles_insert"
    ON public.profiles FOR INSERT
    TO authenticated
    WITH CHECK (public.fn_is_owner());

-- -----------------------------------------------------------------------
-- 8.2 categories — semua read, owner/manager write
-- -----------------------------------------------------------------------
DROP POLICY IF EXISTS "categories_select" ON public.categories;
DROP POLICY IF EXISTS "categories_write"  ON public.categories;
DROP POLICY IF EXISTS "categories_delete" ON public.categories;

CREATE POLICY "categories_select"
    ON public.categories FOR SELECT
                                                              TO authenticated USING (true);

CREATE POLICY "categories_insert"
    ON public.categories FOR INSERT
    TO authenticated
    WITH CHECK (public.fn_is_owner_or_manager());

CREATE POLICY "categories_update"
    ON public.categories FOR UPDATE
                                               TO authenticated
                                               USING (public.fn_is_owner_or_manager());

CREATE POLICY "categories_delete"
    ON public.categories FOR DELETE
TO authenticated
    USING (public.fn_is_owner());

-- -----------------------------------------------------------------------
-- 8.3 units — sama dengan categories
-- -----------------------------------------------------------------------
CREATE POLICY "units_select"
    ON public.units FOR SELECT TO authenticated USING (true);

CREATE POLICY "units_insert"
    ON public.units FOR INSERT TO authenticated
    WITH CHECK (public.fn_is_owner_or_manager());

CREATE POLICY "units_update"
    ON public.units FOR UPDATE TO authenticated
                                          USING (public.fn_is_owner_or_manager());

CREATE POLICY "units_delete"
    ON public.units FOR DELETE TO authenticated
    USING (public.fn_is_owner());

-- -----------------------------------------------------------------------
-- 8.4 suppliers
-- -----------------------------------------------------------------------
CREATE POLICY "suppliers_select"
    ON public.suppliers FOR SELECT TO authenticated USING (true);

