-- -----------------------------------------------------------------------
-- 8.10 transactions
-- -----------------------------------------------------------------------
CREATE POLICY "transactions_select"
    ON public.transactions FOR SELECT TO authenticated
                                                 USING (
                                                 cashier_id = auth.uid() OR public.fn_is_owner_or_manager()
                                                 );

CREATE POLICY "transactions_insert"
    ON public.transactions FOR INSERT TO authenticated
    WITH CHECK (cashier_id = auth.uid());

-- Update: kasir hanya bisa ubah transaksinya sendiri selama pending
CREATE POLICY "transactions_update"
    ON public.transactions FOR UPDATE TO authenticated
                                                 USING (
                                                 (cashier_id = auth.uid() AND status = 'pending')
                                                 OR public.fn_is_owner_or_manager()
                                                 );

-- Delete: hanya owner
CREATE POLICY "transactions_delete"
    ON public.transactions FOR DELETE TO authenticated
    USING (public.fn_is_owner());

-- -----------------------------------------------------------------------
-- 8.11 transaction_items
-- -----------------------------------------------------------------------
CREATE POLICY "txn_items_select"
    ON public.transaction_items FOR SELECT TO authenticated
                                                                                            USING (
                                                                                            EXISTS (
                                                                                            SELECT 1 FROM public.transactions t
                                                                                            WHERE t.id = transaction_id
                                                                                            AND (t.cashier_id = auth.uid() OR public.fn_is_owner_or_manager())
                                                                                            )
                                                                                            );

CREATE POLICY "txn_items_insert"
    ON public.transaction_items FOR INSERT TO authenticated
    WITH CHECK (
        EXISTS (
            SELECT 1 FROM public.transactions t
            WHERE t.id = transaction_id AND t.cashier_id = auth.uid()
        )
    );

