-- -----------------------------------------------------------------------
-- 9.2 product-images — PUBLIC READ, owner/manager write
-- -----------------------------------------------------------------------
DROP POLICY IF EXISTS "product_images_public_read" ON storage.objects;
DROP POLICY IF EXISTS "product_images_auth_upload"  ON storage.objects;
DROP POLICY IF EXISTS "product_images_auth_delete"  ON storage.objects;

CREATE POLICY "product_images_public_read"
    ON storage.objects FOR SELECT
                                                     USING (bucket_id = 'product-images');

CREATE POLICY "product_images_auth_upload"
    ON storage.objects FOR INSERT
    TO authenticated
    WITH CHECK (
        bucket_id = 'product-images'
        AND public.fn_is_owner_or_manager()
    );

CREATE POLICY "product_images_auth_update"
    ON storage.objects FOR UPDATE
                                             TO authenticated
                                             USING (
                                             bucket_id = 'product-images'
                                             AND public.fn_is_owner_or_manager()
                                             );

CREATE POLICY "product_images_auth_delete"
    ON storage.objects FOR DELETE
TO authenticated
    USING (
        bucket_id = 'product-images'
        AND public.fn_is_owner()
    );

-- -----------------------------------------------------------------------
-- 9.3 receipts — authenticated read (milik sendiri atau owner), kasir upload
-- -----------------------------------------------------------------------
DROP POLICY IF EXISTS "receipts_owner_read"    ON storage.objects;
DROP POLICY IF EXISTS "receipts_cashier_upload" ON storage.objects;

CREATE POLICY "receipts_auth_read"
    ON storage.objects FOR SELECT
                                                TO authenticated
                                                USING (
                                                bucket_id = 'receipts'
                                                AND (
                                                -- Path format: receipts/{user_id}/{filename}
                                                (storage.foldername(name))[1] = auth.uid()::text
                                                OR public.fn_is_owner_or_manager()
                                                )
                                                );

CREATE POLICY "receipts_cashier_upload"
    ON storage.objects FOR INSERT
    TO authenticated
    WITH CHECK (
        bucket_id = 'receipts'
        AND (storage.foldername(name))[1] = auth.uid()::text
    );

CREATE POLICY "receipts_delete"
    ON storage.objects FOR DELETE
TO authenticated
    USING (
        bucket_id = 'receipts'
        AND public.fn_is_owner()
    );

-- -----------------------------------------------------------------------
-- 9.4 documents — hanya owner/manager
-- -----------------------------------------------------------------------
DROP POLICY IF EXISTS "documents_auth_read"   ON storage.objects;
DROP POLICY IF EXISTS "documents_auth_write"  ON storage.objects;
DROP POLICY IF EXISTS "documents_auth_delete" ON storage.objects;

CREATE POLICY "documents_auth_read"
    ON storage.objects FOR SELECT
                                                     TO authenticated
