        bucket_id = 'documents'
        AND public.fn_is_owner()
    );

-- =====================================================================
-- 10. VIEWS (helper untuk laporan)
-- =====================================================================

-- View: stok rendah
CREATE OR REPLACE VIEW public.v_low_stock_products AS
SELECT
    p.id,
    p.sku,
    p.name,
    p.cached_stock AS current_stock,
    p.low_stock_threshold,
    p.selling_price,
    c.name AS category_name
FROM public.products p
         LEFT JOIN public.categories c ON c.id = p.category_id
WHERE p.track_stock = true
  AND p.is_active   = true
  AND p.cached_stock <= p.low_stock_threshold
  AND NOT p.has_variants;

-- View: hutang belum lunas
CREATE OR REPLACE VIEW public.v_outstanding_debts AS
SELECT
    d.id,
    d.created_at,
    d.due_date,
    c.name  AS customer_name,
    c.phone AS customer_phone,
    d.amount,
    d.paid_amount,
    d.remaining,
    d.status,
    CASE WHEN d.due_date < CURRENT_DATE AND d.status != 'paid'
         THEN true ELSE false
        END AS is_overdue
FROM public.customer_debts d
         JOIN public.customers c ON c.id = d.customer_id
WHERE d.status != 'paid'
ORDER BY d.due_date ASC NULLS LAST;

-- View: ringkasan shift
CREATE OR REPLACE VIEW public.v_shift_summary AS
SELECT
    s.id AS shift_id,
    s.opened_at,
    s.closed_at,
    s.status,
    p.full_name       AS cashier_name,
    s.opening_cash,
    s.closing_cash,
    s.expected_cash,
    s.cash_difference,
    COUNT(t.id)       AS total_transactions,
    COALESCE(SUM(t.total_amount) FILTER (WHERE t.status = 'completed'), 0) AS total_revenue,
    COALESCE(SUM(t.paid_amount) FILTER (WHERE t.payment_method = 'cash' AND t.status = 'completed'), 0) AS cash_in
FROM public.shifts s
         JOIN public.profiles p ON p.id = s.cashier_id
         LEFT JOIN public.transactions t ON t.shift_id = s.id
GROUP BY s.id, p.full_name;

